CREATE   PROCEDURE sp_CheckPermission
@RoleId INT,
@PageName NVARCHAR(100)
AS

BEGIN
    INSERT INTO Orders
    (
        Id,
        ProductName,
        Quantity,
        Price,
        UserId
    )
    VALUES
    (
        @Id,
        @ProductName,
        @Quantity,
        @Price,
        @UserId
    )
END

CREATE PROCEDURE sp_CreateOrder
    @Id UNIQUEIDENTIFIER,
    @ProductName NVARCHAR(100),
    @Quantity INT,
    @Price DECIMAL(18,2),
    @UserId UNIQUEIDENTIFIER
AS

BEGIN
    INSERT INTO Users
    (
        Id,
        Name,
        Email,
        PasswordHash,
        RoleId,
        MustChangePassword
    )
    VALUES
    (
        @Id,
        @Name,
        @Email,
        @PasswordHash,
        @RoleId,
        @MustChangePassword
    )
END

CREATE PROCEDURE sp_CreateUser
    @Id UNIQUEIDENTIFIER,
    @Name NVARCHAR(100),
    @Email NVARCHAR(100),
    @PasswordHash NVARCHAR(500),
    @RoleId INT,
    @MustChangePassword BIT
AS

BEGIN
    DELETE FROM RefreshTokens
    WHERE UserId = @Id;

    DELETE FROM Orders
    WHERE UserId = @Id;

    DELETE FROM AuditLogs
    WHERE UserId = @Id;

    DELETE FROM Users
    WHERE Id = @Id;
END

